import asyncio


class Scheduler:
    def __init__(self):
        self.jobs = []

    async def inner(self):
        await asyncio.sleep(0.01)
        return 'inner done'

    def nested(self):
        # BUG: already inside event loop; cannot call asyncio.run again
        return asyncio.run(self.inner())

    async def outer(self):
        return self.nested()


async def outer():
    s = Scheduler()
    return await s.outer() if asyncio.iscoroutine(s.outer()) else s.outer()


if __name__ == '__main__':
    asyncio.run(outer())
